func TestSetAndGet(t *testing.T) {
	s := New[string]()
	s.Set("key", "value")
	val, ok := s.Get("key")
	if !ok || val != "value" {
		t.Errorf("expected 'value', got %v", val)
	}
}

func TestDelete(t *testing.T) {
	s := New[int]()
	s.Set("key", 42)
	s.Delete("key")
	_, ok := s.Get("key")
	if ok {
		t.Error("expected key to be deleted")
	}
}

func TestTypeSafety(t *testing.T) {
	s := New[float64]()
	s.Set("pi", 3.14)
	val, _ := s.Get("pi")
	// val is float64, no type assertion needed
	if val != 3.14 {
		t.Errorf("expected 3.14, got %f", val)
	}
}
